#include <stdio.h>
#include <stdlib.h>

int main(void)
{
    int code, tentatives = 0;
    int acces = 0;  // drapeau : 0 = refusé, 1 = autorisé

    while (tentatives < 3 && acces == 0)
    {
        printf("Entrez le code d'acces (tentative %d/3) : ", tentatives+1);
        scanf("%d", &code);

        if (code == 1234)
        {
            acces = 1;
        }
        else
        {
            tentatives++;
            if (tentatives < 3)
                printf("Code errone. Reessayez.\n");
        }
    }

    if (acces == 1)
        printf("Acces autorise. Bonne navigation !\n");
    else
        printf("Compte bloque. Contactez l'administrateur.\n");

    return 0;
}
